// Parse PROD_DYNASSUR_2026.csv → table mouvements_production
// On lit le header dynamiquement pour mapper les colonnes
const item = $input.first();
if (!item.binary) throw new Error('Pas de données binaires');
const propName = item.binary.data ? 'data' : Object.keys(item.binary)[0];
const binMeta = item.binary[propName];
let buffer;
if (binMeta && binMeta.data) buffer = Buffer.from(binMeta.data, 'base64');
else buffer = await this.helpers.getBinaryDataBuffer(0, propName);
let txt = buffer.toString('utf8').replace(/^\uFEFF/, '');
const lines = txt.split(/\r?\n/);

const clean = (s) => (s || '').toString().trim().replace(/^\"|\"$/g, '');
const toISO = (s) => {
  s = (s || '').toString().trim();
  const p = s.split('/');
  if (p.length === 3 && p[2].length === 4) return `${p[2]}-${p[1].padStart(2,'0')}-${p[0].padStart(2,'0')}`;
  return null;
};

// Parser le header pour mapper dynamiquement
const headers = lines[0].split(';').map(h => clean(h).toLowerCase()
  .replace(/é|è|ê/g,'e').replace(/à|â/g,'a').replace(/ô/g,'o')
  .replace(/[^a-z0-9_]/g,'_').replace(/__+/g,'_').replace(/^_|_$/g,''));

const rows = [];
for (let i = 1; i < lines.length; i++) {
  const line = lines[i];
  if (!line || !line.trim()) continue;
  const f = line.split(';');
  if (f.length < 5) continue;
  const obj = {};
  headers.forEach((h, idx) => { if (h) obj[h] = clean(f[idx]); });

  // Mapping vers colonnes Supabase
  rows.push({
    dossier:      obj['dossier'] || null,
    type_prod:    obj['type_production'] || obj['type_prod'] || clean(f[0]),
    agent_code:   obj['sa'] || obj['agent_code'] || null,
    annee:        parseInt(obj['annee']) || new Date().getFullYear(),
    mois:         obj['mois'] ? String(obj['mois']).padStart(2,'0') : null,
    num_contrat:  obj['police'] || obj['num_contrat'] || null,
    client_nom:   obj['nom'] || null,
    branche:      obj['domaine'] || obj['branche'] || null,
    compagnie:    obj['compagnie'] || null,
    gestionnaire: obj['gestionnaire_nom'] || obj['gestionnaire'] || null,
  });
}

const CHUNK = 1000;
const out = [];
for (let i = 0; i < rows.length; i += CHUNK) {
  out.push({ json: { rows: rows.slice(i, i + CHUNK), total: rows.length, lot: (i/CHUNK)+1 } });
}
if (out.length === 0) out.push({ json: { rows: [], total: 0, lot: 0 } });
return out;
